def index_document(index, doc_id, document):
    try:
        es.index(index=index, id=doc_id, body=document)
        logger.info(f'Document indexed: {doc_id} in index {index}')
    except Exception as e:
        logger.error(f'Error indexing document: {e}')

def search_index(index, query):
    try:
        response = es.search(index=index, body={"query": {"match": {"message": query}}})
        logger.info(f'Search results for query "{query}" in index {index}')
        return response['hits']['hits']
    except Exception as e:
        logger.error(f'Error searching index: {e}')
        return []

def aggregate_logs(index):
    try:
        response = es.search(index=index, body={
            "size": 0,
            "aggs": {
                "log_levels": {
                    "terms": {
                        "field": "level.keyword"
                    }
                }
            }
        })
        logger.info(f'Log aggregation results from index {index}')
        return response['aggregations']['log_levels']['buckets']
    except Exception as e:
        logger.error(f'Error aggregating logs: {e}')
        return []

